<script setup>import {computed} from 'vue';import {useRoute,useRouter} from 'vue-router';import {courses} from '../courses';import {useEnrollmentStore} from '../stores/enrollment';const route=useRoute(),router=useRouter(),store=useEnrollmentStore();const course=computed(()=>courses.find(c=>c.id===Number(route.params.id)));async function enroll(){await store.fetchAndEnroll(route.params.id);router.push('/profile')}</script><template><main v-if="course"><RouterLink to="/courses">← Courses</RouterLink><h1>{{course.name}}</h1><p>{{course.code}} · {{course.credits}} credits</p><button @click="enroll">Enroll</button></main><main v-else><h1>Course not found</h1></main></template>
